body:
Consider this simple example:

```
module add(
    input a,
    input b,
    output [1:0] c
);
    assign c = a + b;
endmodule

module top;

    typedef struct packed
    {
        struct packed
        {
            logic a;
            logic b;
            logic c;
            logic d;
        } test;
    } my_struct_t;

    my_struct_t my_struct;

    logic [1:0] c;

    add add (
        .a(my_struct.test.a),
        .b(my_struct.test.b),
        .c(c)
    );

    initial begin
        my_struct.test = 4'b0101;
     
        #1;
        
        $display("%d", my_struct.test.a);
        $display("%d", my_struct.test.b);
        $display("%d", my_struct.test.c);
        $display("%d", my_struct.test.d);
        $display("%d", my_struct.test);
        $display("%d", my_struct);
        $display("%d", c);
    end

endmodule
```

The output is as follows:

```
iverilog -o Vtop.vvp -g2012 top.sv 
top.sv:26: warning: Port 1 (a) of add expects 1 bits, got 4.
top.sv:26:        : Pruning 3 high bits of the expression.
top.sv:26: warning: Port 2 (b) of add expects 1 bits, got 4.
top.sv:26:        : Pruning 3 high bits of the expression.
vvp Vtop.vvp
 0
 1
 0
 1
 5
 5
1
```

It seems as if the width of the individual members is the same as for the entire nested structure.

If this example is reduced to a simple structure like this:

```
module top;

    typedef struct packed
    {
        logic a;
        logic b;
        logic c;
        logic d;
    } my_struct_t;

    my_struct_t my_struct;

    logic [1:0] c;

    add add (
        .a(my_struct.a),
        .b(my_struct.b),
        .c(c)
    );

    initial begin
        my_struct = 4'b0101;
     
        #1;
        
        $display("%d", my_struct.a);
        $display("%d", my_struct.b);
        $display("%d", my_struct.c);
        $display("%d", my_struct.d);
        $display("%d", my_struct);
        $display("%d", c);
    end

endmodule
```

We get the expected output without any warning from iverilog:

```
iverilog -o Vtop.vvp -g2012 top.sv 
vvp Vtop.vvp
0
1
0
1
 5
1
```

